import React, { useState } from 'react';



const App = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [otp, setOtp] = useState('');
  const [accountDetails, setAccountDetails] = useState('');
  const [isVerified, setIsVerified] = useState(false);


  const handleSubmit = (e) => {
    e.preventDefault();
    // Verify OTP here
    setIsVerified(true);
    setAccountDetails('Account Details will be displayed after OTP verification');
  };


  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#B7D7CD] p-4 rounded-md shadow-md w-full max-w-sm">
        <form onSubmit={handleSubmit}>
          <div className="mb-4">
            <label className="block text-sm font-medium text-gray-900" htmlFor="username">
              Username
            </label>
            <input
              type="text"
              id="username"
              className="block py-2 pl-10 text-sm text-gray-900 bg-gray-50 border border-gray-300 rounded-md focus:ring-blue-500 focus:border-blue-500"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
            />
          </div>
          <div className="mb-4">
            <label className="block text-sm font-medium text-gray-900" htmlFor="password">
              Password
            </label>
            <input
              type="password"
              id="password"
              className="block py-2 pl-10 text-sm text-gray-900 bg-gray-50 border border-gray-300 rounded-md focus:ring-blue-500 focus:border-blue-500"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
            />
          </div>
          <button
            type="submit"
            className="group relative w-full flex justify-center py-2 px-4 border border-transparent text-sm font-medium rounded-md text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
          >
            <span className="absolute left-0 inline-flex h-full w-3 bg-white"></span>
            <span className="relative text-sm font-medium">Verify OTP</span>
          </button>
        </form>
        {isVerified && (
          <div className="text-lg font-bold mt-4">
            {accountDetails}
          </div>
        )}
      </div>
    </div>
  );
};


export default App;
